const fileName = "20260409-Chargerent-1.1.1.0-OU-FOTA.pac";
const publicBaseUrl = "http://34.56.244.66:1880";
const fileUrl = publicBaseUrl + "/firmware-download/" + encodeURIComponent(fileName);
const fileSize = Buffer.isBuffer(msg.payload) ? msg.payload.length : Number(msg.payload?.length || 0);

if (!fileSize) {
    msg.statusCode = 500;
    msg.headers = { "Content-Type": "application/json; charset=utf-8" };
    msg.payload = {
        code: 500,
        type: 0,
        data: "",
        msg: "Firmware file is missing or empty",
        time: Date.now()
    };
    return msg;
}

msg.statusCode = 200;
msg.headers = {
    "Content-Type": "application/json; charset=utf-8",
    "Cache-Control": "no-store"
};
msg.payload = {
    code: 200,
    type: 0,
    data: `${fileName},${fileSize},${fileUrl}`,
    msg: "ok",
    time: Date.now()
};

node.warn(`Firmware metadata ${msg.req?.path || msg.req?.url || ""}: ${msg.payload.data}`);
return msg;

const headers = msg.req?.headers || {};
const remoteAddress = msg.req?.ip || msg.req?.connection?.remoteAddress || msg.req?.socket?.remoteAddress || "";
msg._firmwareDownload = {
    fileName: "20260409-Chargerent-1.1.1.0-OU-FOTA.pac",
    requestedAt: new Date().toISOString(),
    method: msg.req?.method || "GET",
    url: msg.req?.originalUrl || msg.req?.url || "",
    remoteAddress,
    userAgent: headers["user-agent"] || "",
    range: headers.range || ""
};
node.warn(`Firmware download requested by ${remoteAddress || "unknown"} ${msg._firmwareDownload.range ? "range=" + msg._firmwareDownload.range : "full"}`);
return msg;

const fileName = "20260409-Chargerent-1.1.1.0-OU-FOTA.pac";
const buffer = Buffer.isBuffer(msg.payload) ? msg.payload : Buffer.from(msg.payload || []);
const total = buffer.length;
const headers = msg.req?.headers || {};
const range = String(headers.range || "").trim();

if (!total) {
    msg.statusCode = 500;
    msg.headers = { "Content-Type": "text/plain; charset=utf-8" };
    msg.payload = "Firmware file is missing or empty";
    return msg;
}

msg.headers = {
    "Content-Type": "application/octet-stream",
    "Accept-Ranges": "bytes",
    "Cache-Control": "no-store",
    "X-Firmware-File": fileName
};

if (range) {
    const match = range.match(/^bytes=(\d*)-(\d*)$/);
    if (!match) {
        msg.statusCode = 416;
        msg.headers["Content-Range"] = `bytes */${total}`;
        msg.headers["Content-Length"] = "0";
        msg.payload = Buffer.alloc(0);
        return msg;
    }

    let start = match[1] === "" ? 0 : Number(match[1]);
    let end = match[2] === "" ? total - 1 : Number(match[2]);
    if (!Number.isFinite(start) || !Number.isFinite(end) || start < 0 || end < start || start >= total) {
        msg.statusCode = 416;
        msg.headers["Content-Range"] = `bytes */${total}`;
        msg.headers["Content-Length"] = "0";
        msg.payload = Buffer.alloc(0);
        return msg;
    }

    end = Math.min(end, total - 1);
    msg.statusCode = 206;
    msg.payload = buffer.slice(start, end + 1);
    msg.headers["Content-Range"] = `bytes ${start}-${end}/${total}`;
    msg.headers["Content-Length"] = String(msg.payload.length);
    node.warn(`Firmware download served range ${start}-${end}/${total}`);
    return msg;
}

msg.statusCode = 200;
msg.headers["Content-Length"] = String(total);
msg.payload = buffer;
node.warn(`Firmware download served full file ${fileName}, ${total} bytes`);
return msg;
